var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"메스헤르츠 채널에서 전해드리는 속보입니다.","JPN":"マスヘルツチャンネルからの速報です。","ENG":"Breaking news, here from the Masshertz channel.","TWN":"來自梅斯赫茲頻道的快報。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"금일 갑작스러운 침식사태 발발로 인해 소란이 빚어지고 있는 가운데, SNS 등지에서는 또다른 소식으로 논란이 불거지고 있습니다.","JPN":"本日、侵食事態騒動が起きている中、SNSなどでは別の話題が広まっています。","ENG":"The abrupt Corruption disaster that occurred today has been causing chaos, while the citizens are in disarray from the news that has been spreading through social media.","TWN":"今天突然爆發的侵蝕事件讓市民一片譁然，而同時在社群網路上傳出的另一個消息引發了爭議。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드 관리국의 시니어로 알려진 인물이 살해되었으며, 이 현장을 캡처한 다수의 사진들이 유포된 것인데요.","JPN":"シャレード管理局のシニアと思わしき人物が殺害され、その現場を撮影した写真が多数流布されました。","ENG":"A man, known as the Senior of Charade City Management, has been found murdered, and several pictures of the crime scene have been leaked.","TWN":"據悉，疑似查雷德管理局Senior的人物被殺害，現場的一些照片已經在社群網路上流傳開來。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 사진은 빠르게 삭제되었으나 그 진위 여부에 대해 관리국 관계자 측에선 아직 별다른 해명이 없는 것으로…","JPN":"この写真は直ちに削除されましたが、その真偽のほどについては管理局の関係者から、まだ弁明されていない模様です……","ENG":"The photos were quickly removed, but the Administration has made no particular statement about the authenticity of the photos...","TWN":"這些照片很快就被刪除，但管理局仍未對照片真實與否公開表態……"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"세상이 미쳐 돌아가네. 샤레이드 시니어가 죽은 것도 모자라 현장 사진이 퍼진다고?","JPN":"世の中どうかしてるわね。シャレードのシニアが死んだだけでも騒ぎなのに、現場写真まで広まってるの？","ENG":"The world's gone mad. A Charade Senior is dead, and now the scene's gone viral?","TWN":"這個世界真是瘋了。查雷德Senior死了還不夠，現場照片還被傳播出去？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"멸망할 거면 나 죽은 뒤에나 할 것이지. 왜 한창 팔팔할 때 이 지경이야?","JPN":"滅びるにしても、私が死んだ後にしてほしいわ。なんで一番元気なときにこんな目に遭うのよ？","ENG":"If the world's going to end, it could at least wait till after I'm dead. Why now, while I'm still in my prime?","TWN":"如果要滅亡，至少等我死後再來吧。為什麼偏偏在我正活躍的時候變成這樣？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"메데이아 경. 부단장님으로부터의 전언입니다.","JPN":"メデイア卿。副団長からの伝言です。","ENG":"Dame Medea, a message from the Deputy.","TWN":"美狄亞。副團長的傳話。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"곧 블루시프트 단원들이 현장에 도착한다고 합니다.","JPN":"まもなくブルーシフトの団員たちが現場に到着するとのことです。","ENG":"Blue Shift members will be arriving on-site shortly.","TWN":"藍移小組成員即將抵達現場。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"동부 방어선은 이걸로 안심이네요. 그 외, 다른 쪽은 어떤가요?","JPN":"東部防御線はこれで安心ですわね。その他の状況はどうですか？","ENG":"The eastern defense line is secured.. What about the other sections?","TWN":"東部防線這樣就放心了。那麼其他地方怎麼樣？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"서부 뉴 하이랜드 및 남동부 메리데일 방어선 모두, 타 태스크포스와 협력 중에 있습니다.","JPN":"西部のニューハイランドおよび南東部のメリーデールの防御線も、他のタスクフォースと連携中です。","ENG":"Western New Highland and southeastern Meridale defense lines are currently collaborating with other TASKFORCEs.","TWN":"西部新高地和東南部梅裡代爾防線均在與其他特遣勢力合作中。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"추가적인 지원이 필요하다 여기신다면 저희 쪽에서 인력을 차출하겠습니다.","JPN":"追加支援が必要とお考えでしたら、こちらから人員を派遣いたします。","ENG":"If you feel additional support is needed, we can deploy some of our own.","TWN":"如果你覺得需要額外的支援，我們會從這邊派遣人力。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮습니다. 정말 급한 상황이라면 상부에서 연락이 올 거예요.","JPN":"結構です。もし本当に急ぎの事態なら、上層部から直接連絡が来るはずですから。","ENG":"No need. If it were urgent, headquarters would've called already.","TWN":"沒關係。如果真的有緊急情況，上級會聯絡的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"본부의 인원도 많지 않으니, 우선-.","JPN":"本部の人手も限られていますし、まずは……","ENG":"Our personnel here aren't unlimited either, so for now–","TWN":"總部人員也不多，所以先-"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"메데이아 경! 로터스 지부 단원으로부터의 연락입니다!","JPN":"メデイア卿！　ロータス支部の団員からの報告です！","ENG":"Dame Medea! A report just came in from the Lotus branch!","TWN":"美狄亞！來自洛德斯分部成員的聯繫！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"샤레이드의 침식사태 발발 이후, 로터스 국경지대에 도움을 주던 중.","JPN":"シャレードの侵食事態発生後、ロータス国境地帯で支援に当たっていた中で……","ENG":"While assisting near the Lotus border during the Charade Corruption disaster,","TWN":"在查雷德的侵蝕事件爆發後，協助洛德斯邊境地區。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"입국 심사를 거친 명단을 확인하던 차에 익숙한 이름을 발견했다고 합니다!","JPN":"入国審査を経た名簿に見覚えのある名前を発見したそうです！","ENG":"they reviewed the entry logs and spotted a familiar name!","TWN":"在檢查入境審查名單時，發現了一個熟悉的名字！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"익숙한 이름이요?","JPN":"見覚えのある名前……？","ENG":"A familiar name?","TWN":"耳熟的名字嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"그, 그게 오지만… 아니, 줄리아 레온하르트가 로터스 국경을 넘었다고 합니다.","JPN":"そ、それが……オジマン……いえ、ジュリア・レオンハルトがロータスの国境を越えたとのことです。","ENG":"It's Ozym– I mean, Julia... Julia Leonhardt crossed the Lotus border.","TWN":"那，那是喔…不，聽說茱莉亞·里恩哈特越過了洛德斯邊境。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"샤레이드 관리국 관계자의 말에 의하면 상부의 명령 없는 독단이라더군요.","JPN":"シャレード管理局関係者によると、上層部の命令なしに独断で動いたそうで。","ENG":"According to the Administration sources, she acted on her own without orders from above.","TWN":"據查雷德管理局的相關人員說，這是未經上級命令的擅自行動。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"현장의 단원들도 본부의 판단을 기다리고 있습니다만. 어떻게 할까요?","JPN":"現場の隊員たちも本部の判断を待っていますが、どうしましょう？","ENG":"The knights on-site are awaiting further instructions. How shall we proceed?","TWN":"現場的隊員們也在等待總部的判斷。我們該怎麼辦？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_ZODIAC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……잠시만요. 생각을 조금 정리할게요.","JPN":"……少し考えを整理させてください。","ENG":"...Give me a moment. I need to think.","TWN":"……稍等。我整理一下思緒。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 이런 상황에 관리국 공인 카운터가 자리를 비운다고?","JPN":"どういうこと？　こんな状況で、管理局公認のカウンターが持ち場を離れるなんて？","ENG":"What is this? An Administration confirmed Counter gone rogue in a crisis like this?","TWN":"怎麼回事？在這種情況下，管理局認證的制裁者竟然不在場？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"줄리아는 바보가 아니야. 관리국에 보고 없이 움직인 데에는 분명 이유가 있어.","JPN":"ジュリアはバカじゃない。管理局に報告もせずに動くのには、それ相応の理由があるはず。","ENG":"Julia is no fool. If she acted without reporting it, she must've had a reason.","TWN":"茱莉亞不是傻瓜。她沒有向管理局報告就行動，肯定有原因。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이번 침식 사태와 관련 있는 일이라면 상황을 방치할 수도 없는 노릇인데…….","JPN":"今回の侵食事態に関わることなら、見過ごすわけにもいかない……","ENG":"If it's tied to this Corruption disaster, we can't just sit back and watch...","TWN":"如果這件事與這次侵蝕事件有關，那就不能放任不管了……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……짜증나. 원래 이런 판단은 내 몫이 아니라고.","JPN":"……いやになるわ。こんなの、本来私が判断することじゃないのに。","ENG":"...Ugh. This kind of decision isn't supposed to be my job.","TWN":"……真煩。這種判斷本來就不該由我來做。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"메데이아 경. 무슨 일이라도 있으십니까?","JPN":"メデイア卿。何かご心配事でも？","ENG":"Is something wrong, Dame Medea?","TWN":"美狄亞。有什麼事情嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아무것도 아니니 발 빠른 인원들을 몇 추려주세요. 제가 직접 로터스로 향하겠습니다.","JPN":"何でもありません。動きの早い人員を何名か選んでください。私が直接ロータスへ向かいます。","ENG":"It's nothing. Just select a few fast movers. I'll head to Lotus myself.","TWN":"沒什麼大不了的，挑選幾個行動迅速的人。我會親自前往洛德斯。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"하지만 그 줄리아 레온하르트 아닙니까?","JPN":"ですが、あのジュリア・レオンハルトですよ？","ENG":"But it's Julia Leonhardt.","TWN":"但是那不是茱莉亞·里恩哈特嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"제 입으로 말하기 뭐하지만, 별 이유 없이 로터스로 향했을 수도 있습니다.","JPN":"私の口から言うのも何ですが、深い理由もなくロータスへ行った可能性もあります。","ENG":"With all due respect, she might've gone there for no reason at all.","TWN":"雖然不好意思自己說，但可能沒有特別原因就去了洛德斯。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"상부의 지시가 없다면 그녀의 책임소재는 기사단에 있습니다.","JPN":"上からの命令がないのなら、彼女について責任を負うのは騎士団です。","ENG":"Without orders from above, the responsibility still falls on the Order.","TWN":"如果沒有上級的指示，她的責任歸屬在騎士團。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"때문에 방관할 상황이 아닐뿐더러…. 솔직히, 이유 없이 움직였다는 생각은 들지 않아요.","JPN":"ですから、傍観していられる状況ではありませんし……正直、理由もなく動いたとは思えません。","ENG":"We can't afford to ignore it... And honestly, I don't believe she acted without a reason.","TWN":"因此，這不是可以袖手旁觀的情況……說實話，我不覺得這是無緣無故的行動。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"꽤 직감이 좋은 편이거든요. 레온하르트 경은.","JPN":"かなり勘が鋭い方なんです、レオンハルト卿は。","ENG":"Dame Leonhardt's intuition has always been sharp.","TWN":"里恩哈特的直覺相當不錯呢。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"로터스 지부에 연락해주세요.","JPN":"ロータス支部に連絡をお願いします。","ENG":"Contact the Lotus branch.","TWN":"請聯絡洛德斯分部。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"흔적을 쫓아, 그녀와 합류하겠습니다.","JPN":"足取りを追って、彼女と合流します。","ENG":"I'll track her down and meet up with her.","TWN":"追蹤痕跡，與她會合。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"하… 난리도 아니네. 이게 대체 무슨 소란이야?","JPN":"はあ……なんなんだ、この騒ぎは。","ENG":"*Sigh...* What's going on?","TWN":"下……真是亂套了。這到底是什麼騷動？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"야. 이러다 진짜 세상이 멸망이라도 하는 거 아니냐?","JPN":"おい、本当にこのまま世界が滅ぶんじゃないのか？","ENG":"At this rate, the world really is ending, huh?","TWN":"喂，這樣下去世界真的會滅亡嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"으, 그극…….","JPN":"う、ぐうっ……","ENG":"G-grhk...","TWN":"呃、呃呃……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"너 몸을 왜 그렇게 떨어? 혹시 몸살이라도 걸렸냐?","JPN":"お前、なんでそんなに震えてるんだ？　熱でもあるのか？","ENG":"Why are you shaking like that? You sick or something?","TWN":"你為什麼抖得這麼厲害？是不是得了感冒？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"기다려. 내가 가서 약이라도 가져올게.","JPN":"待ってろ、薬を持ってきてやるから。","ENG":"Hold on, I'll grab some meds–","TWN":"等一下。我去拿點藥來。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아아~. 시시해. 단장님이 너무 똑똑해서 내 몸만 편하잖아…….","JPN":"あ～あ。つまんない。団長が賢すぎて、アタシの出番がないじゃん……","ENG":"Agh, how boring. Captain's too smart, so I don't even have to lift a finger...","TWN":"啊啊～真無聊。團長太聰明了，讓我只顧著享受……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"편한 거, 좋은 거~? 싸우질 않으니 통 모르겠어…….","JPN":"楽なのって、いいこと～？　戦わないから、全然わかんない……","ENG":"Easy's nice and all, but I don't get to fight, so what's the point...?","TWN":"舒服的東西，好東西～？因為不打架，所以完全不知道……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"꼬마야. 여긴 어떻게 들어온 거니?","JPN":"お嬢ちゃん、ここにはどうやって入ってきたんだい？","ENG":"Hey, kid. How'd you get in here?","TWN":"小傢伙，你是怎麼進來的？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"미안하지만 여긴 외부인 출입 금지란다. 혹시 밖이 무서워서 도망쳐온 거라면-.","JPN":"悪いけど、ここは関係者以外は立ち入りは禁止だよ。もし外が怖くて逃げてきたのなら……","ENG":"Sorry, but civilians aren't allowed here. If you came in because you were scared–","TWN":"抱歉，這裡禁止外人進入。如果是因為害怕外面而逃進來的話——。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"잠깐. 밖은 분명 다른 단원들이 경비를 서고 있었을 텐데?","JPN":"待てよ。外にはほかの隊員が警備していたはず……？","ENG":"Wait a minute. Weren't there guards outside?","TWN":"等等。外面應該有其他成員在警戒吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"앤드류! 밖의 녀석들에게 연락해! 뭔가 문제가 생긴 모양이야!","JPN":"アンドリュー！　外の連中に連絡しろ！　何か問題が起きてる！","ENG":"Andrew! Contact the others out front! Something's wrong!","TWN":"安德魯！聯絡外面的人！好像出了什麼問題！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_NPC_ZODIAC_B","text":{"KOREA":"으윽, 크으으윽……!","JPN":"うっ、くううっ……！","ENG":"Ugh, grghhk...!","TWN":"呃呃，咳呃呃呃……！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"애, 앤드류? 너 갑자기 왜 그래?","JPN":"ア、アンドリュー？　どうしたんだ急に！？","ENG":"A-Andrew? What's going on with you?","TWN":"喂，安德魯？你突然怎麼了？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"조금만 기다려봐! 내가 가서 사람을 불러올-.","JPN":"待ってろ！　俺が人を呼んでく……","ENG":"Hang on! I'll go get hel–","TWN":"稍等一下！我去叫人來-。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KNIGHT_PRIDE_NPC_A","text":{"KOREA":"커억…….","JPN":"がはっ……","ENG":"Kggghh...","TWN":"唔……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_PRIDE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"리액트… 리액터~? 그걸 챙기라고 했는데 어디 있는지도 모르겠고…….","JPN":"リアクト……リアクターだっけ？　あれを探せって言われたけど、どこにあるかもわかんないし……","ENG":"React... Reactor? I was told to grab it, but I don't even know what it looks like...","TWN":"反應……電抗器～？讓我去拿那個，但我連在哪都不知道……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"경비가 많다 보니 이 녀석 저 녀석 죽이고는 있는데, 이래서야 한세월이잖아~.","JPN":"警備多いし、とりあえず片っ端から殺してるけど、これじゃラチがあかないよ～","ENG":"With all the guards around, I've had to kill this one and that one, but it's taking forever.","TWN":"因為有很多守衛，我這邊殺了不少人，但這樣下去要花很長時間啊～。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"아~. 모르겠다.","JPN":"あ～もう、知らない。","ENG":"Ugh, whatever.","TWN":"啊～不管了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASCELLA_ZODIAC_NULL_NULL","text":{"KOREA":"계속 죽이다 보면 언젠가는 나오겠지, 뭐.","JPN":"とにかく殺しまくってれば、いつか出てくるでしょ、たぶん。","ENG":"If I just keep killing, I'll probably find it eventually.","TWN":"繼續殺下去，總有一天會出現的，沒關係。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"방어선에서 한눈 팔기 있어, 부단장? 곧 제3파가 올 거라고!","JPN":"防御線でよそ見なんてしてる場合なの、副団長？　もうすぐ第3波が来るよ！","ENG":"Eyes on the defense line, Deputy! The third wave is about to come!","TWN":"在防線分心嗎，副指揮官？第三波馬上就要來了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"제3파! 옵니다!","JPN":"第3波、来ます！","ENG":"Third wave! Incoming!","TWN":"第三波！來了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저기요-! 부단장님? 지금 제3파가 온다니까요!","JPN":"あのー！　副団長！？　今、第3波が来るって言ってるんですけど！","ENG":"Hellooo? Deputy? The third wave is coming!","TWN":"喂——！副團長？現在第三波要來了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아니, 생각해보니 이상하잖아! 지금 역할이 반대가 되어버렸다고!!","JPN":"……いや、待って。よく考えたらおかしくない！？　今、役割が逆になってるって！！","ENG":"Wait a sec, isn't this backwards?! I'm the one calling you to focus now?!","TWN":"不對，仔細想想很奇怪啊！現在職責反過來了！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 언니, 힘내세요! 제가 열심히 치료해드릴게요!","JPN":"リブさん、頑張ってください！　私、一生懸命治療しますから！","ENG":"Hang in there, Liv! I'll heal you as much as you need!","TWN":"莉芙姊姊，加油！我會努力為你治療的！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에, 에리어스? 갑자기 튀어나오면 위험해!","JPN":"ア、アリウス！？　急に飛び出したら危ないよ！","ENG":"A-Arius?! Don't just pop in like that, it's dangerous!","TWN":"埃、埃里奧斯？突然冒出來很危險的！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이상하군. 아까부터 본부와 연락이 닿지 않는다.","JPN":"おかしい。さっきから本部とまったく連絡が取れない。","ENG":"Something's off. I haven't been able to reach HQ.","TWN":"好奇怪。從剛才開始就無法與總部取得聯絡。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP"},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"침식파의 영향이 거세니 단순 기우일 수도 있지만…….","JPN":"侵食波の影響が強いから、ただの杞憂かもしれないが……","ENG":"It might just be the Corruption ray interference, but...","TWN":"侵蝕波的影響很強烈，可能只是單純的杞人憂天……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_A","text":{"KOREA":"양옆에서 침식체가 더 몰려옵니다! 부상자들이 많아서 저지선 유지가 힘들어요!","JPN":"左右から更に侵食体が迫ってきます！　負傷者も多く、もう防御線が保てません！","ENG":"More C.O.s approaching from both flanks! Too many wounded! We're losing the line!","TWN":"兩側有更多侵蝕體湧來！傷患太多，難以維持防線！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MERCENARY_NPC_CHARADE_B","text":{"KOREA":"바리케이트의 폭탄도 거의 소진됐습니다! 이대로 가면 밀릴 거예요!","JPN":"バリケードの爆弾もほとんど残っていません！　このままだと押し切られます！","ENG":"We're almost out of explosives for the barricades! We'll get pushed back at this rate!","TWN":"路障的炸彈也快用完了！這樣下去會被擊退的！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_CHARADE_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERCENARY_NPC_CHARADE_B","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……아니, 지금은 다른 걸 신경 쓸 때가 아니야.","JPN":"……いや、今は他のことに気を取られてる場合ではない。","ENG":"...No. I can't afford to worry about anything else right now.","TWN":"……不，現在不是關心其他事情的時候。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"리브 경, 한솔 경! <color=#ffd34c>무구</color>를 개방하겠습니다!","JPN":"リブ卿、ヤガミ卿！　<color=#ffd34c>武具</color>を開放します！","ENG":"Dame Liv, Sir Hansol! I'm unleashing the <color=#ffd34c>Armament</color>!","TWN":"莉芙、楊瀚！我決定開放<color=#ffd34c>武具</color>！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"폭탄이 남아있는 바리케이드를 적의 중심지로 던져주세요!","JPN":"爆弾が残っているバリケードを、敵の中心部に向けて投げ込んでください！","ENG":"Throw the remaining explosive barricade toward the enemy's core!","TWN":"請將剩餘的炸彈扔向敵人的中心地帶的路障！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"네! 맡겨만 주세요!","JPN":"はい！　任せてください！","ENG":"Got it! Leave it to me!","TWN":"是！請交給我吧！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오케이-. 최대한 멀리 던지면 되지?","JPN":"オッケー。できるだけ遠くに投げればいいんだね？","ENG":"Okay! Just gotta toss it as far as I can, right?","TWN":"喔，好的。儘量扔得遠一點就行，對吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흐아아압-!","JPN":"はあああっ！","ENG":"HRAAHH!","TWN":"呵啊啊啊——！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장, 지금!","JPN":"副団長、今だよ！","ENG":"Deputy, now!","TWN":"副團長，現在！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"걱정 마시죠, 리브 경.","JPN":"ご心配なく、リブ卿。","ENG":"Don't worry, Dame Liv.","TWN":"別擔心，莉芙。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이 한방으로… 확실히 끝내겠습니다!","JPN":"この一撃で……確実に仕留めます！","ENG":"This blow... will end it for good!","TWN":"這一擊……我會徹底解決掉！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하아… 하아…","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"呼……呼……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"침식체는 줄어드는데… 이 불길한 기운은 좀처럼 가시질 않네요.","JPN":"侵食体は減ってるのに……この不気味さはなかなか消えませんね。","ENG":"The C.O.s are diminishing... but this eerie feeling isn't going away.","TWN":"侵蝕體正在減少……但這種不祥的感覺並沒有消失。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으음, 그러게. 땀을 많이 흘려서 그런가?","JPN":"うーん、そうだね。汗をかきすぎたせいかな？","ENG":"Mmm, you're right. Maybe it's because we're sweating a lot.","TWN":"嗯，確實。是因為流了很多汗嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"야, 한솔아. 나 땀냄새 많이 나냐?","JPN":"ちょっと、イチロウ。私って汗臭い？","ENG":"Hey, Hansol. Do I smell bad?","TWN":"嘿，楊瀚，我身上有汗味嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"우왓?! 그런 말 하면서 들이대지 마요!","JPN":"うわっ！？　ちょっとくっつかないでくださいよ！","ENG":"Whoa! You can't just get close while saying that!","TWN":"哇？！別靠這麼近！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"한솔 경의 말대로군요. 침식체들을 쓰러트려도 침식파장이 줄어드는 느낌이 없습니다.","JPN":"ヤガミ卿の言うとおりです。侵食体を倒しても、侵食波が減る気配がありません。","ENG":"It's as Hansol said. I don't get the feeling that the Corruption ray is diminishing, even though we're defeating the C.O.s.","TWN":"楊瀚說得沒錯。即使擊殺了侵蝕體，侵蝕波也依然不減。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응? 진짜루?","JPN":"え？　マジ！？","ENG":"Huh? Really?","TWN":"嗯？真的嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그러고보니 하늘도 평소보다 어두운 느낌인데. 기분 탓인가?","JPN":"そういえば、空がいつもより暗いね。気のせいかな？","ENG":"Now that you mention it, the sky looks darker than usual. What do you think?","TWN":"話說天空似乎比往常更暗了，是我看錯了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어?","JPN":"あれれ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"여러분! 하늘에서 하얀 눈이 내리기 시작했어요!","JPN":"みなさん！　空から雪が降り始めましたよ！","ENG":"Look! Snow's falling from the sky!","TWN":"各位！開始下雪了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하하, 에리어스. 겨울도 아닌데 갑자기 그게 무슨 소리…","JPN":"はは、アリウス。冬でもないのになに言って……","ENG":"Ha ha, Arius. It's not even winter, what do you–","TWN":"哈哈，埃里奧斯。現在又不是冬天，你在說什……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"응? 정말 눈이 오잖아?","JPN":"えっ……？　本当に雪が降ってる。","ENG":"Huh? It's really snowing.","TWN":"咦？真的下雪了？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"와우, 기상조절기가 있는 관리도시에서 갑자기 눈이 내릴 정도면 바깥은 훨씬 춥겠는데?","JPN":"ワオ、気象調節器がある管理都市でいきなり雪が降るくらいなら、外はもっと寒いかも。","ENG":"Wow, if an Administration City with a weather controller is seeing snow, that must mean it's much colder outside.","TWN":"哇，連一個有氣象調節器的管理城市裡也突然下雪，那麼外面一定更加寒冷。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"비행기는 결항일 테니 당분간 고향에는 못 가겠다!","JPN":"飛行機は欠航だから、しばらく地元には帰れないね！","ENG":"Flights are probably canceled, so I guess I'm not going home for a while!","TWN":"我的航班應該已經被取消了，暫時回不了家了！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그 클리포트 게임이 끝나면, 당분간은 평화가 지속될 것이라 기대했습니다만…","JPN":"あのクリフォトゲームが終れば、しばらくは平和になると期待していましたが……","ENG":"I thought there would be peace once the Qliphoth Game had ended...","TWN":"我本以為逆卡巴拉遊戲結束後，會迎來短暫的和平……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그건 그저 제 바람일 뿐이었을지도 모르겠군요.","JPN":"それは、ただ私の望みだったのかもしれません。","ENG":"But maybe that was just wishful thinking.","TWN":"也許這只是我的一廂情願。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"원로원에도 이 사실을 알려야겠습니다.","JPN":"元老院にもこのことを知らせましょう。","ENG":"I should notify the Elders of this.","TWN":"我得讓元老院知道這件事。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"우선, 본부로 돌아가도록 하죠.","JPN":"まずは、本部へ戻るのが先かと。","ENG":"For now, let's return to HQ.","TWN":"我們先回總部吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};